import{_ as a,o as r,c as t,a2 as i}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Sécurité","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/security.md","filePath":"fr/guide/security.md"}'),s={name:"fr/guide/security.md"};function n(o,e,c,l,d,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="securite" tabindex="-1">Sécurité <a class="header-anchor" href="#securite" aria-label="Permalink to &quot;Sécurité&quot;">​</a></h1><p>Clearance est passé par un audit de sécurité dédié avant publication, suivi de deux passes de renforcement supplémentaires avant la sortie. Points forts : plafonds anti-élévation de privilèges sur chaque chemin d&#39;attribution de permission (attributions directes comme synchronisation au niveau du rôle), surcharges de contexte à autorité de refus, un assainisseur SVG en liste blanche, un espace de noms de permission <code>clearance-*</code> protégé, et des directives Blade sûres pour les invités.</p><h2 id="acces-au-panneau-et-permissions-d-ecriture-fines" tabindex="-1">Accès au panneau et permissions d&#39;écriture fines <a class="header-anchor" href="#acces-au-panneau-et-permissions-d-ecriture-fines" aria-label="Permalink to &quot;Accès au panneau et permissions d&#39;écriture fines&quot;">​</a></h2><p>L&#39;accès en lecture à l&#39;ensemble du panneau nécessite la permission <code>clearance-access</code> (vérifiée via <code>can()</code>, jamais <code>hasRole()</code>). Les opérations d&#39;écriture sur chaque section sont contrôlées par une permission dédiée et délégable - toutes créées par <code>clearance:install</code> et assignées à <code>super_admin</code> :</p><table tabindex="0"><thead><tr><th>Permission</th><th>Contrôle</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Créer / modifier / supprimer des permissions</td></tr><tr><td><code>clearance-roles-write</code></td><td>Créer / modifier / supprimer des rôles et leurs attributions de permissions</td></tr><tr><td><code>clearance-guards-write</code></td><td>Créer / modifier / supprimer des gardes</td></tr><tr><td><code>clearance-settings-write</code></td><td>Modifier les métadonnées d&#39;affichage, icônes, couleurs, rôle par défaut</td></tr><tr><td><code>clearance-users-write</code></td><td>Assigner / retirer des rôles pour un utilisateur spécifique</td></tr></tbody></table><p>Si une ligne de permission fine n&#39;existe pas du tout en base de données (un état hérité pré-amorçage), le contrôle se rabat sur <code>clearance-access</code> pour la rétrocompatibilité.</p><h2 id="espace-de-noms-clearance-protege" tabindex="-1">Espace de noms <code>clearance-*</code> protégé <a class="header-anchor" href="#espace-de-noms-clearance-protege" aria-label="Permalink to &quot;Espace de noms `clearance-*` protégé&quot;">​</a></h2><p>Les permissions <code>clearance-*</code> sont réservées : elles ne peuvent être créées, renommées, supprimées, ou ajoutées à aucun rôle en dehors du flux d&#39;installation du package lui-même - même par un acteur <code>super_admin</code> pour le rôle <code>super_admin</code> lui-même.</p><h2 id="plafonds-anti-elevation-de-privileges" tabindex="-1">Plafonds anti-élévation de privilèges <a class="header-anchor" href="#plafonds-anti-elevation-de-privileges" aria-label="Permalink to &quot;Plafonds anti-élévation de privilèges&quot;">​</a></h2><p>Chaque chemin d&#39;attribution de permission dans Clearance applique un plafond afin qu&#39;un acteur ne puisse jamais accorder plus qu&#39;il ne détient lui-même :</p><ul><li><strong>Rôles plafonds</strong> - un rôle peut déclarer un rôle parent dont l&#39;ensemble de permissions agit comme une limite supérieure. Toute permission excédentaire est silencieusement retirée lors de <code>RoleService::setParent()</code> et à chaque synchronisation de permission ultérieure - aucune exception, aucun message d&#39;erreur. Retirer des permissions d&#39;un parent propage automatiquement la suppression à chaque enfant. Voir <a href="/clearance-docs/fr/features/roles.html">Rôles</a> pour l&#39;API complète du plafond.</li><li><strong>Module Utilisateurs</strong> - l&#39;attribution de rôle comme les attributions de permission directes/par surcharge appliquent toutes deux un plafond de privilège : un acteur non-<code>super_admin</code> ne peut pas modifier ses propres attributions, et ne peut pas accorder une permission qu&#39;il ne détient pas lui-même. Voir <a href="/clearance-docs/fr/features/users.html">Utilisateurs</a>.</li></ul><h2 id="surcharges-de-contexte-a-autorite-de-refus" tabindex="-1">Surcharges de contexte à autorité de refus <a class="header-anchor" href="#surcharges-de-contexte-a-autorite-de-refus" aria-label="Permalink to &quot;Surcharges de contexte à autorité de refus&quot;">​</a></h2><p>Les surcharges de permission par contexte (<code>clr_ctx_overrides</code>) prennent en charge <code>forced_on</code> et <code>forced_off</code>. <code>forced_off</code> l&#39;emporte toujours - même sur une permission accordée par un rôle global. Il n&#39;existe aucun chemin permettant à une attribution de priorité inférieure de surcharger un refus explicite. Voir <a href="/clearance-docs/fr/guide/architecture.html#how-resolution-works">Architecture</a> pour l&#39;ordre de résolution complet.</p><h2 id="assainissement-svg" tabindex="-1">Assainissement SVG <a class="header-anchor" href="#assainissement-svg" aria-label="Permalink to &quot;Assainissement SVG&quot;">​</a></h2><p>Chaque icône fournie par l&#39;utilisateur (métadonnées d&#39;affichage de rôle/garde dans le panneau Paramètres) passe par un assainisseur en liste blanche à la fois avant le stockage et au moment du rendu - pas une simple vérification unique à l&#39;envoi.</p><h2 id="directives-blade-sures-pour-les-invites" tabindex="-1">Directives Blade sûres pour les invités <a class="header-anchor" href="#directives-blade-sures-pour-les-invites" aria-label="Permalink to &quot;Directives Blade sûres pour les invités&quot;">​</a></h2><p><code>@canin</code> et <code>@hasrolein</code> se résolvent tous deux de façon sûre (renvoient <code>false</code>) pour un utilisateur invité - elles ne lèvent jamais d&#39;exception.</p><h2 id="le-contournement-de-gate-est-a-l-echelle-de-l-application" tabindex="-1">Le contournement de Gate est à l&#39;échelle de l&#39;application <a class="header-anchor" href="#le-contournement-de-gate-est-a-l-echelle-de-l-application" aria-label="Permalink to &quot;Le contournement de Gate est à l&#39;échelle de l&#39;application&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> (défaut <code>false</code>) contrôle si le rôle <code>super_admin</code> contourne toutes les vérifications Laravel <code>can()</code> / <code>Gate::allows()</code> / policy à l&#39;échelle globale, via un hook <code>Gate::before()</code>.</p><div class="warning custom-block"><p class="custom-block-title">Non limité au panneau</p><p>Une fois activé, tout utilisateur détenant <code>super_admin</code> contourne toutes les vérifications de Gate à l&#39;échelle de l&#39;application - pas seulement les vérifications du panneau Clearance. Activez-le délibérément. Voir <a href="/clearance-docs/fr/features/super-admin.html">Super Admin</a> pour la détection d&#39;alias et le comportement de promotion.</p></div><h2 id="points-d-attention-lies-a-la-securite" tabindex="-1">Points d&#39;attention liés à la sécurité <a class="header-anchor" href="#points-d-attention-lies-a-la-securite" aria-label="Permalink to &quot;Points d&#39;attention liés à la sécurité&quot;">​</a></h2><ul><li><code>forced_off</code> l&#39;emporte toujours - même sur une permission accordée par un rôle global.</li><li>Un rôle plafond ne fait que retirer, jamais accorder - définir un parent permissif n&#39;accorde rien à l&#39;enfant par lui-même.</li><li>Le contournement de Gate (<code>super_admin_gate_bypass</code>) s&#39;applique à toute l&#39;application, pas uniquement au panneau.</li><li>Le module Utilisateurs est désactivé par défaut (<code>modules.users = false</code>).</li><li>Les permissions <code>clearance-*</code> sont intouchables en dehors du flux d&#39;installation, même pour <code>super_admin</code>.</li><li>Exécutez toujours <code>clearance:install</code>, jamais un simple <code>migrate</code>, sur une installation neuve - voir <a href="/clearance-docs/fr/guide/installation.html">Installation</a>.</li></ul><h2 id="voir-aussi" tabindex="-1">Voir aussi <a class="header-anchor" href="#voir-aussi" aria-label="Permalink to &quot;Voir aussi&quot;">​</a></h2><ul><li><a href="/clearance-docs/fr/guide/architecture.html">Architecture</a> - ordre de priorité de résolution et schéma <code>clr_*</code></li><li><a href="/clearance-docs/fr/features/roles.html">Rôles</a> - les rôles plafonds en détail</li><li><a href="/clearance-docs/fr/features/users.html">Utilisateurs</a> - le plafond de privilège sur l&#39;attribution de rôle/permission</li><li><a href="/clearance-docs/fr/features/super-admin.html">Super Admin</a> - contournement de Gate et détection d&#39;alias</li></ul>',24)])])}const h=a(s,[["render",n]]);export{m as __pageData,h as default};
